 1	import { createOpenAiApi } from "./openai.ts";
 2	import type { Message, Tool } from "./types.ts";
 3	
 4	async function testText() {
 5	    console.log("\n=== TEST 1: 纯文本 ===\n");
 6	    const api = createOpenAiApi({
 7	        name: process.env.PROVIDER || "openai",
 8	        baseURL: process.env.DEEPSEEK_BASE_URL || "https://api.openai.com",
 9	        apiKey: process.env.DEEPSEEK_API_KEY ?? process.env.OPENAI_API_KEY ?? "",
10	    });
11	
12	    const messages: Message[] = [
13	        { role: "user", content: "用中文说'你好',就三个字,不要别的" },
14	    ];
15	
16	    for await (const ev of api.stream({
17	        model: process.env.MODEL || "deepseek-v4-flash",
18	        messages,
19	    })) {
20	        console.log(JSON.stringify(ev));
21	    }
22	}
23	
24	async function testTool() {
25	    console.log("\n=== TEST 2: 工具调用 ===\n");
26	    const api = createOpenAiApi({
27	        name: process.env.PROVIDER || "openai",
28	        baseURL: process.env.DEEPSEEK_BASE_URL || "https://api.openai.com",
29	        apiKey: process.env.DEEPSEEK_API_KEY ?? process.env.OPENAI_API_KEY ?? "",
30	    });
31	
32	    const messages: Message[] = [
33	        { role: "user", content: "用 bash 工具执行 ls 命令" },
34	    ];
35	
36	    const tools: Tool[] = [{
37	        name: "bash",
38	        description: "run a bash command and return stdout",
39	        parameters: {
40	            type: "object",
41	            properties: {
42	                command: { type: "string", description: "shell command" },
43	            },
44	            required: ["command"],
45	        } as any,
46	    }];
47	
48	    for await (const ev of api.stream({
49	        model: process.env.MODEL || "deepseek-v4-flash",
50	        messages,
51	        tools,
52	    })) {
53	        console.log(JSON.stringify(ev));
54	    }
55	}
56	
57	async function main() {
58	    await testText();
59	    await testTool();
60	}
61	
62	main().catch(err => {
63	    console.error("SMOKE TEST FAILED:", err);
64	    process.exit(1);
65	});
